(function (root) {
  'use strict';

  function LazyLoad(options) {
    this.options = options || {};
    this.selector = this.options.elements_selector || 'img';
    this.dataSrc = 'data-' + (this.options.data_src || 'src');
    this.threshold = this.options.threshold || 600;
    this.init();
  }

  LazyLoad.prototype.load = function (element) {
    var src = element.getAttribute(this.dataSrc);
    if (!src || element.classList.contains('loaded')) return;
    element.src = src;
    element.removeAttribute(this.dataSrc);
    element.classList.add('loaded');
  };

  LazyLoad.prototype.init = function () {
    var self = this;
    this.update();
    root.addEventListener('scroll', function () { self.update(); }, { passive: true });
    root.addEventListener('resize', function () { self.update(); });
    setTimeout(function () { self.update(); }, 300);
    setTimeout(function () { self.update(); }, 1200);
    var ticks = 0;
    var timer = setInterval(function () {
      self.update();
      ticks += 1;
      if (ticks >= 30 || !document.querySelector(self.selector + '[' + self.dataSrc + ']')) {
        clearInterval(timer);
      }
    }, 500);
  };

  LazyLoad.prototype.update = function () {
    var self = this;
    var elements = document.querySelectorAll(this.selector + '[' + this.dataSrc + ']');
    elements.forEach(function (element) {
      var rect = element.getBoundingClientRect();
      if (rect.top < root.innerHeight + self.threshold && rect.bottom > -self.threshold) {
        self.load(element);
      }
    });
  };

  root.LazyLoad = LazyLoad;
  if (typeof globalThis !== 'undefined') globalThis.LazyLoad = LazyLoad;

  function boot() {
    if (!root.lazyLoadInstance) {
      root.lazyLoadInstance = new LazyLoad({
        elements_selector: 'img',
        threshold: 0,
        data_src: 'lazy-src'
      });
    } else if (root.lazyLoadInstance.update) {
      root.lazyLoadInstance.update();
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }
})(typeof window !== 'undefined' ? window : globalThis);
